package com.schwab.urlShortener.service;

import org.springframework.stereotype.Component;

import java.net.InetAddress;
import java.net.URI;
import java.net.UnknownHostException;
import java.util.Set;

/**
 * Validates URLs for security and format requirements.
 * 
 * Security controls:
 * - Allowlist of safe schemes (http, https only) to prevent XSS via javascript:, data:, etc.
 * - Rejection of private/internal IP addresses to prevent SSRF attacks against internal infrastructure
 * 
 * Known limitations:
 * - DNS rebinding attacks: An attacker controlling DNS could pass validation with a public IP,
 *   then change DNS to resolve to a private IP between validation and redirect time (TOCTOU).
 * - IP obfuscation in hostnames is detected, but new encoding schemes may emerge.
 * - Does not protect against phishing, malware domains, or other content-based threats.
 */
@Component
public class UrlValidator {
    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");

    // RFC 1918 private address ranges
    private static final String[] PRIVATE_IP_PATTERNS = {
        "^10\\..*",           // 10.0.0.0/8
        "^172\\.(1[6-9]|2[0-9]|3[0-1])\\..*",  // 172.16.0.0/12
        "^192\\.168\\..*"     // 192.168.0.0/16
    };

    public void validate(String url) {
        if (url == null || url.trim().isEmpty()) {
            throw new InvalidUrlException("URL cannot be empty");
        }

        URI uri;
        try {
            uri = URI.create(url);
        } catch (IllegalArgumentException e) {
            throw new InvalidUrlException("Invalid URL format: " + e.getMessage());
        }

        validateScheme(uri);
        validateHost(uri);
    }

    private void validateScheme(URI uri) {
        String scheme = uri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            throw new InvalidUrlException(
                "URL scheme must be http or https. Found: " + scheme
            );
        }
    }

    private void validateHost(URI uri) {
        String host = uri.getHost();
        if (host == null || host.trim().isEmpty()) {
            throw new InvalidUrlException("URL must have a valid host");
        }

        // Check for localhost variations
        if (isLocalhost(host)) {
            throw new InvalidUrlException("URLs pointing to localhost are not allowed");
        }

        // Try to resolve and check if it's a private/internal address
        try {
            InetAddress address = InetAddress.getByName(host);
            if (isPrivateOrInternalAddress(address)) {
                throw new InvalidUrlException("URLs pointing to private or internal IP addresses are not allowed");
            }
        } catch (UnknownHostException e) {
            // If we can't resolve the host, we'll allow it through
            // The redirect will fail naturally if the host doesn't exist
            // This avoids being overly restrictive for valid public domains with temporary DNS issues
        }
    }

    private boolean isLocalhost(String host) {
        String lowerHost = host.toLowerCase();
        return lowerHost.equals("localhost") || 
               lowerHost.equals("localhost.localdomain") ||
               lowerHost.startsWith("localhost.");
    }

    private boolean isPrivateOrInternalAddress(InetAddress address) {
        // Check loopback (127.0.0.0/8 for IPv4, ::1 for IPv6)
        if (address.isLoopbackAddress()) {
            return true;
        }

        // Check link-local (169.254.0.0/16 for IPv4, fe80::/10 for IPv6)
        if (address.isLinkLocalAddress()) {
            return true;
        }

        // Check site-local/private (deprecated for IPv6 but still checked)
        if (address.isSiteLocalAddress()) {
            return true;
        }

        // Additional check for RFC 1918 private ranges using string matching
        // This catches cases where the Java API might not flag them
        String hostAddress = address.getHostAddress();
        for (String pattern : PRIVATE_IP_PATTERNS) {
            if (hostAddress.matches(pattern)) {
                return true;
            }
        }

        return false;
    }
}

package com.schwab.urlShortener.service;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import static org.junit.jupiter.api.Assertions.*;

class UrlValidatorTest {

    private final UrlValidator validator = new UrlValidator();

    @Test
    void validHttpUrl_shouldPass() {
        assertDoesNotThrow(() -> validator.validate("http://example.com"));
    }

    @Test
    void validHttpsUrl_shouldPass() {
        assertDoesNotThrow(() -> validator.validate("https://example.com"));
    }

    @Test
    void validUrlWithPath_shouldPass() {
        assertDoesNotThrow(() -> validator.validate("https://example.com/path/to/resource"));
    }

    @Test
    void validUrlWithQueryParams_shouldPass() {
        assertDoesNotThrow(() -> validator.validate("https://example.com/path?param=value&other=123"));
    }

    @Test
    void nullUrl_shouldThrowException() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate(null)
        );
        assertTrue(ex.getMessage().contains("cannot be empty"));
    }

    @Test
    void emptyUrl_shouldThrowException() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("")
        );
        assertTrue(ex.getMessage().contains("cannot be empty"));
    }

    @Test
    void javascriptScheme_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("javascript:alert('xss')")
        );
        assertTrue(ex.getMessage().contains("scheme must be http or https"));
    }

    @Test
    void dataScheme_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("data:text/html,<script>alert('xss')</script>")
        );
        assertTrue(ex.getMessage().contains("scheme must be http or https"));
    }

    @Test
    void fileScheme_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("file:///etc/passwd")
        );
        assertTrue(ex.getMessage().contains("scheme must be http or https"));
    }

    @Test
    void ftpScheme_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("ftp://files.example.com/file.txt")
        );
        assertTrue(ex.getMessage().contains("scheme must be http or https"));
    }

    @Test
    void localhostUrl_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://localhost:8080/admin")
        );
        assertTrue(ex.getMessage().contains("localhost"));
    }

    @Test
    void localhostVariation_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://localhost.localdomain/admin")
        );
        assertTrue(ex.getMessage().contains("localhost"));
    }

    @Test
    void loopbackIpv4_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://127.0.0.1/admin")
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @Test
    void loopbackIpv4Variant_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://127.1.1.1/admin")
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://10.0.0.1/admin",
        "http://10.255.255.255/admin",
        "http://10.1.2.3:8080/resource"
    })
    void rfc1918ClassA_shouldBeRejected(String url) {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate(url)
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://172.16.0.1/admin",
        "http://172.31.255.255/admin",
        "http://172.20.10.5:8080/resource"
    })
    void rfc1918ClassB_shouldBeRejected(String url) {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate(url)
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://192.168.0.1/admin",
        "http://192.168.255.255/admin",
        "http://192.168.1.1:8080/resource"
    })
    void rfc1918ClassC_shouldBeRejected(String url) {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate(url)
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://169.254.0.1/metadata",
        "http://169.254.169.254/latest/meta-data"
    })
    void linkLocalAddress_shouldBeRejected(String url) {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate(url)
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @Test
    void ipv6Loopback_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://[::1]/admin")
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @Test
    void ipv6LinkLocal_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http://[fe80::1]/admin")
        );
        assertTrue(ex.getMessage().contains("private or internal"));
    }

    @Test
    void urlWithoutHost_shouldBeRejected() {
        InvalidUrlException ex = assertThrows(
            InvalidUrlException.class,
            () -> validator.validate("http:///path")
        );
        assertTrue(ex.getMessage().contains("valid host"));
    }
}

package com.schwab.urlShortener.service;

import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.domain.ShortLinkRepository;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class ShortLinkServiceTest {

    @Mock
    private ShortLinkRepository repository;

    @Mock
    private UrlValidator urlValidator;

    @Mock
    private ShortCodeGenerator shortCodeGenerator;

    @InjectMocks
    private ShortLinkService service;

    @Test
    void createShortLink_withValidUrl_shouldSucceed() {
        String longUrl = "https://example.com/very/long/path";
        String shortCode = "abc123";

        when(shortCodeGenerator.generate()).thenReturn(shortCode);
        when(repository.existsByShortCode(shortCode)).thenReturn(false);
        when(repository.save(any(ShortLink.class))).thenAnswer(i -> i.getArgument(0));

        ShortLink result = service.createShortLink(longUrl);

        assertNotNull(result);
        assertEquals(longUrl, result.getLongUrl());
        assertEquals(shortCode, result.getShortCode());

        verify(urlValidator).validate(longUrl);
        verify(repository).save(any(ShortLink.class));
    }

    @Test
    void createShortLink_withInvalidUrl_shouldThrowException() {
        String invalidUrl = "not-a-valid-url";

        doThrow(new InvalidUrlException("Invalid URL format"))
            .when(urlValidator).validate(invalidUrl);

        assertThrows(InvalidUrlException.class, () -> {
            service.createShortLink(invalidUrl);
        });

        verify(urlValidator).validate(invalidUrl);
        verify(repository, never()).save(any());
    }

    @Test
    void createShortLink_withCollision_shouldRetry() {
        String longUrl = "https://example.com";
        String firstCode = "abc123";
        String secondCode = "def456";

        when(shortCodeGenerator.generate())
            .thenReturn(firstCode)
            .thenReturn(secondCode);
        when(repository.existsByShortCode(firstCode)).thenReturn(true);
        when(repository.existsByShortCode(secondCode)).thenReturn(false);
        when(repository.save(any(ShortLink.class))).thenAnswer(i -> i.getArgument(0));

        ShortLink result = service.createShortLink(longUrl);

        assertEquals(secondCode, result.getShortCode());
        verify(shortCodeGenerator, times(2)).generate();
    }

    @Test
    void getLongUrl_withExistingShortCode_shouldReturnUrl() {
        String shortCode = "abc123";
        String longUrl = "https://example.com";
        ShortLink link = new ShortLink(longUrl, shortCode);

        when(repository.findByShortCode(shortCode)).thenReturn(Optional.of(link));

        Optional<String> result = service.getLongUrl(shortCode);

        assertTrue(result.isPresent());
        assertEquals(longUrl, result.get());
    }

    @Test
    void getLongUrl_withNonExistentShortCode_shouldReturnEmpty() {
        String shortCode = "nonexistent";

        when(repository.findByShortCode(shortCode)).thenReturn(Optional.empty());

        Optional<String> result = service.getLongUrl(shortCode);

        assertFalse(result.isPresent());
    }

    @Test
    void incrementClickCount_shouldUpdateRepository() {
        String shortCode = "abc123";

        service.incrementClickCount(shortCode);

        verify(repository).incrementClickCount(shortCode);
    }

    @Test
    void createShortLink_validatesUrl_beforePersisting() {
        String longUrl = "https://example.com";
        String shortCode = "abc123";

        when(shortCodeGenerator.generate()).thenReturn(shortCode);
        when(repository.existsByShortCode(shortCode)).thenReturn(false);
        when(repository.save(any(ShortLink.class))).thenAnswer(i -> i.getArgument(0));

        service.createShortLink(longUrl);

        verify(urlValidator).validate(longUrl);
    }

    @Test
    void createShortLink_withInternalUrl_shouldRejectAtServiceLevel() {
        String internalUrl = "http://192.168.1.1/admin";

        doThrow(new InvalidUrlException("URLs pointing to private or internal IP addresses are not allowed"))
            .when(urlValidator).validate(internalUrl);

        InvalidUrlException ex = assertThrows(InvalidUrlException.class, () -> {
            service.createShortLink(internalUrl);
        });

        assertTrue(ex.getMessage().contains("private or internal"));
        verify(urlValidator).validate(internalUrl);
        verify(repository, never()).save(any());
    }

    @Test
    void createShortLink_withLocalhostUrl_shouldRejectAtServiceLevel() {
        String localhostUrl = "http://localhost:8080/admin";

        doThrow(new InvalidUrlException("URLs pointing to localhost are not allowed"))
            .when(urlValidator).validate(localhostUrl);

        InvalidUrlException ex = assertThrows(InvalidUrlException.class, () -> {
            service.createShortLink(localhostUrl);
        });

        assertTrue(ex.getMessage().contains("localhost"));
        verify(urlValidator).validate(localhostUrl);
        verify(repository, never()).save(any());
    }
}

package com.schwab.urlShortener.api;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.service.InvalidUrlException;
import com.schwab.urlShortener.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import static org.hamcrest.Matchers.containsString;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(ShortLinkController.class)
class ShortLinkControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private ShortLinkService shortLinkService;

    @Test
    void createShortLink_withValidUrl_shouldReturn201() throws Exception {
        String longUrl = "https://example.com/very/long/path";
        String shortCode = "abc123";
        ShortLink link = new ShortLink(longUrl, shortCode);

        when(shortLinkService.createShortLink(longUrl)).thenReturn(link);

        CreateShortLinkRequest request = new CreateShortLinkRequest(longUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isCreated())
            .andExpect(header().exists("Location"))
            .andExpect(header().string("Location", containsString("/r/" + shortCode)))
            .andExpect(jsonPath("$.shortCode").value(shortCode))
            .andExpect(jsonPath("$.longUrl").value(longUrl))
            .andExpect(jsonPath("$.shortUrl").value(containsString("/r/" + shortCode)));
    }

    @Test
    void createShortLink_withNullUrl_shouldReturn400() throws Exception {
        CreateShortLinkRequest request = new CreateShortLinkRequest(null);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.title").value("Bad Request"))
            .andExpect(jsonPath("$.detail").value(containsString("longUrl")));
    }

    @Test
    void createShortLink_withEmptyUrl_shouldReturn400() throws Exception {
        CreateShortLinkRequest request = new CreateShortLinkRequest("");

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.title").value("Bad Request"))
            .andExpect(jsonPath("$.detail").value(containsString("longUrl")));
    }

    @Test
    void createShortLink_withInvalidUrl_shouldReturn400() throws Exception {
        String invalidUrl = "not-a-url";

        when(shortLinkService.createShortLink(invalidUrl))
            .thenThrow(new InvalidUrlException("Invalid URL format"));

        CreateShortLinkRequest request = new CreateShortLinkRequest(invalidUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(content().contentType("application/problem+json"))
            .andExpect(jsonPath("$.title").value("Invalid URL"))
            .andExpect(jsonPath("$.detail").value(containsString("Invalid URL format")));
    }

    @Test
    void createShortLink_withDangerousScheme_shouldReturn400() throws Exception {
        String dangerousUrl = "javascript:alert('xss')";

        when(shortLinkService.createShortLink(dangerousUrl))
            .thenThrow(new InvalidUrlException("URL scheme must be http or https"));

        CreateShortLinkRequest request = new CreateShortLinkRequest(dangerousUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(content().contentType("application/problem+json"))
            .andExpect(jsonPath("$.title").value("Invalid URL"));
    }

    @Test
    void createShortLink_withInternalIpAddress_shouldReturn400() throws Exception {
        String internalUrl = "http://192.168.1.1/admin";

        when(shortLinkService.createShortLink(internalUrl))
            .thenThrow(new InvalidUrlException("URLs pointing to private or internal IP addresses are not allowed"));

        CreateShortLinkRequest request = new CreateShortLinkRequest(internalUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(content().contentType("application/problem+json"))
            .andExpect(jsonPath("$.title").value("Invalid URL"))
            .andExpect(jsonPath("$.detail").value(containsString("private or internal")));
    }

    @Test
    void createShortLink_withLocalhostUrl_shouldReturn400() throws Exception {
        String localhostUrl = "http://localhost:8080/admin";

        when(shortLinkService.createShortLink(localhostUrl))
            .thenThrow(new InvalidUrlException("URLs pointing to localhost are not allowed"));

        CreateShortLinkRequest request = new CreateShortLinkRequest(localhostUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(content().contentType("application/problem+json"))
            .andExpect(jsonPath("$.title").value("Invalid URL"))
            .andExpect(jsonPath("$.detail").value(containsString("localhost")));
    }

    @Test
    void createShortLink_withMalformedJson_shouldReturn400() throws Exception {
        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content("{invalid json"))
            .andExpect(status().isBadRequest());
    }

    @Test
    void createShortLink_withUrlExceedingMaxLength_shouldReturn400() throws Exception {
        String veryLongUrl = "https://example.com/" + "a".repeat(2048);

        CreateShortLinkRequest request = new CreateShortLinkRequest(veryLongUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.title").value("Bad Request"))
            .andExpect(jsonPath("$.detail").value(containsString("longUrl")));
    }
}

package com.schwab.urlShortener.service;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Tests for IP address obfuscation techniques that attackers might use to bypass
 * naive IP validation. These techniques exploit the fact that many URL parsers
 * accept alternative representations of IP addresses beyond standard dotted-decimal.
 */
class UrlValidatorIpObfuscationTest {

    private final UrlValidator validator = new UrlValidator();

    @Test
    void decimalNotation_localhost_shouldBeRejected() {
        // 127.0.0.1 in decimal = 2130706433
        String decimalLocalhostUrl = "http://2130706433/admin";

        assertThatThrownBy(() -> validator.validate(decimalLocalhostUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void decimalNotation_privateNetwork_shouldBeRejected() {
        // 192.168.1.1 in decimal = 3232235777
        String decimalPrivateUrl = "http://3232235777/admin";

        assertThatThrownBy(() -> validator.validate(decimalPrivateUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void hexNotation_localhost_shouldBeRejected() {
        // 127.0.0.1 in hex = 0x7f000001
        String hexLocalhostUrl = "http://0x7f000001/admin";

        assertThatThrownBy(() -> validator.validate(hexLocalhostUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void octalNotation_localhost_shouldBeRejected() {
        // 127.0.0.1 in octal per-octet = 0177.0.0.01
        String octalLocalhostUrl = "http://0177.0.0.01/admin";

        assertThatThrownBy(() -> validator.validate(octalLocalhostUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void mixedNotation_privateNetwork_shouldBeRejected() {
        // Mixed representations: 192.168.0x01.1
        String mixedUrl = "http://192.168.0x01.1/admin";

        assertThatThrownBy(() -> validator.validate(mixedUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://0xc0a80001/admin",      // 192.168.0.1 in full hex
        "http://0300.0250.0000.0001/admin", // 192.168.0.1 in full octal
        "http://3232235521/admin"       // 192.168.0.1 in decimal
    })
    void obfuscatedRfc1918Addresses_shouldBeRejected(String url) {
        assertThatThrownBy(() -> validator.validate(url))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void ipv4MappedIpv6_loopback_shouldBeRejected() {
        // IPv4-mapped IPv6 for 127.0.0.1
        String ipv4MappedUrl = "http://[::ffff:127.0.0.1]/admin";

        assertThatThrownBy(() -> validator.validate(ipv4MappedUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void ipv4MappedIpv6_privateNetwork_shouldBeRejected() {
        // IPv4-mapped IPv6 for 192.168.1.1
        String ipv4MappedUrl = "http://[::ffff:192.168.1.1]/admin";

        assertThatThrownBy(() -> validator.validate(ipv4MappedUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void ipv6_uniqueLocal_shouldBeRejected() {
        // fc00::/7 is unique local address range (IPv6 equivalent of private)
        String uniqueLocalUrl = "http://[fc00::1]/admin";

        assertThatThrownBy(() -> validator.validate(uniqueLocalUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void ipv6_siteLocal_shouldBeRejected() {
        // fec0::/10 is deprecated site-local range
        String siteLocalUrl = "http://[fec0::1]/admin";

        assertThatThrownBy(() -> validator.validate(siteLocalUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void normalPublicIp_shouldNotBeRejected() {
        // 8.8.8.8 is Google's public DNS
        String publicIpUrl = "http://8.8.8.8/page";

        // Should not throw - this is a public IP
        validator.validate(publicIpUrl);
    }

    @Test
    void obfuscatedPublicIp_shouldNotBeRejected() {
        // 8.8.8.8 in decimal = 134744072
        String decimalPublicUrl = "http://134744072/page";

        // Should not throw - this is a public IP even when obfuscated
        validator.validate(decimalPublicUrl);
    }

    @Test
    void shorthandLoopback_shouldBeRejected() {
        // 127.1 is a valid shorthand for 127.0.0.1 in many parsers
        String shorthandUrl = "http://127.1/admin";

        assertThatThrownBy(() -> validator.validate(shorthandUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }

    @Test
    void trailingDotHostname_localhost_shouldBeRejected() {
        // Trailing dot is valid DNS syntax
        String trailingDotUrl = "http://localhost./admin";

        assertThatThrownBy(() -> validator.validate(trailingDotUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("localhost");
    }

    @Test
    void uppercaseLocalhost_shouldBeRejected() {
        String uppercaseUrl = "http://LOCALHOST/admin";

        assertThatThrownBy(() -> validator.validate(uppercaseUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("localhost");
    }

    @Test
    void linkLocalIpv6_fullForm_shouldBeRejected() {
        // fe80:: is link-local
        String linkLocalUrl = "http://[fe80:0000:0000:0000:0000:0000:0000:0001]/admin";

        assertThatThrownBy(() -> validator.validate(linkLocalUrl))
            .isInstanceOf(InvalidUrlException.class)
            .hasMessageContaining("private or internal");
    }
}

package com.schwab.urlShortener;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.schwab.urlShortener.api.CreateShortLinkRequest;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import static org.hamcrest.Matchers.containsString;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
class ShortLinkIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Test
    void createShortLink_withPublicUrl_shouldSucceedEndToEnd() throws Exception {
        CreateShortLinkRequest request = new CreateShortLinkRequest("https://www.google.com/search?q=test");

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isCreated())
            .andExpect(content().contentType(MediaType.APPLICATION_JSON))
            .andExpect(jsonPath("$.shortCode").exists())
            .andExpect(jsonPath("$.longUrl").value("https://www.google.com/search?q=test"))
            .andExpect(jsonPath("$.shortUrl").exists())
            .andExpect(header().exists("Location"));
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "http://localhost:8080/admin",
        "http://127.0.0.1/internal",
        "http://10.0.0.1/resource",
        "http://192.168.1.1/config",
        "http://172.16.0.1/secret",
        "http://169.254.169.254/metadata"
    })
    void createShortLink_withInternalUrls_shouldRejectEndToEnd(String internalUrl) throws Exception {
        CreateShortLinkRequest request = new CreateShortLinkRequest(internalUrl);

        mockMvc.perform(post("/api/v1/links")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(content().contentType("application/problem+json"))
            .andExpect(jsonPath("$.title").value("Invalid URL"))
            .andExpect(jsonPath("$.status").value(400))
            .andExpect(jsonPath("$.detail").exists());
    }

    @Test
    void createShortLink_withLocalhostVariation_shouldRejectEndToEnd() throws Exception {
        CreateShortLinkRequest request = new CreateShortLinkRequest("http://localhost.localdomain/page");

